const inputData = $input.all()[0]?.json || {};
const triggerMsg = $items('Telegram Trigger')[0]?.json?.message || {};
const raw = (triggerMsg.caption || triggerMsg.text || '').toString();
const text = raw.replace(/\s+/g,' ').trim();

const anoMatch = text.match(/Ano\s*:?\s*(\d{4})\s*\/?\s*(\d{4})?/i);
const kmMatch = text.match(/Km\s*:?\s*([\d\.]+)\s*(mil)?/i);
const valorMatch = text.match(/Valor\s*:?\s*([\d\.]+)\s*(mil)?/i);

let Ano = '';
if (anoMatch) Ano = anoMatch[1] + (anoMatch[2] ? '/' + anoMatch[2] : '');
let KM = '';
if (kmMatch) { KM = kmMatch[1].replace(/\./g,''); if (kmMatch[2]) KM += '000'; }
let Valor = '';
if (valorMatch) { Valor = valorMatch[1].replace(/\./g,''); if (valorMatch[2]) Valor += '000'; }

let cutIndex = text.length;
[' Ano', ' Km', ' Valor'].forEach(k => {
  const i = text.toLowerCase().indexOf(k.toLowerCase());
  if (i > 0 && i < cutIndex) cutIndex = i;
});
let Modelo = text.substring(0, cutIndex).trim();

const fallback = (v, f='N/D') => (v && v.toString().trim().length>0 ? v : f);

const out = {
  ...inputData,
  Modelo: fallback(Modelo),
  Ano: fallback(Ano),
  KM: fallback(KM),
  Valor: fallback(Valor),
  Marca: fallback(inputData.Marca),
  Versao: fallback(inputData.Versao),
  Cor: fallback(inputData.Cor),
  Combustivel: fallback(inputData.Combustivel),
  Descricao: fallback(text, 'Sem descrição')
};

return [{ json: out }];

